prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?task ?taskName WHERE {
  ?model a bboExt:Model ;
         tai:normalizedId "2f572d235e784b838fa0d7d2a56748ab" ;
         tai:belongsTo ?org .
  ?defs tai:belongsTo ?model .
  ?choreo tai:belongsTo ?defs .

  ?task a bboExt:ChoreographyTask ;
        tai:belongsTo ?choreo ;
        bbo:name ?taskName .

  FILTER(
    CONTAINS(LCASE(STR(?taskName)), LCASE("Process provisioning")) ||
    CONTAINS(LCASE(STR(?taskName)), LCASE("Operations provisioning")))
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?elem ?name ?type WHERE {
  ?model a bboExt:Model ;
         tai:normalizedId "2f572d235e784b838fa0d7d2a56748ab" ;
         tai:belongsTo ?org .
  ?defs tai:belongsTo ?model .
  ?choreo tai:belongsTo ?defs .

  ?elem tai:belongsTo ?choreo ;
        bbo:name ?name .
  ?elem a ?type .
  FILTER(
    CONTAINS(LCASE(STR(?name)), LCASE("provision"))
  )
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?choreo (COUNT(DISTINCT ?elem) AS ?elemCount) (COUNT(DISTINCT ?task) AS ?taskCount) WHERE {
  ?model a bboExt:Model ;
         tai:normalizedId "2f572d235e784b838fa0d7d2a56748ab" ;
         tai:belongsTo ?org .
  ?defs tai:belongsTo ?model .
  ?choreo tai:belongsTo ?defs .

  ?elem tai:belongsTo ?choreo .
  OPTIONAL { ?task a bboExt:ChoreographyTask ; tai:belongsTo ?choreo . }
}
GROUP BY ?choreo
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?model ?modelName ?normId ?origId WHERE {
  ?model a bboExt:Model .
  OPTIONAL { ?model bbo:name ?modelName . }
  OPTIONAL { ?model tai:normalizedId ?normId . }
  OPTIONAL { ?model tai:originalId ?origId . }
  FILTER(
    (BOUND(?normId) && ?normId = "2f572d235e784b838fa0d7d2a56748ab") ||
    (BOUND(?origId) && ?origId = "2f572d235e784b838fa0d7d2a56748ab")
  )
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?taskName ?task WHERE {
  ?model a bboExt:Model ;
         tai:originalId "2f572d235e784b838fa0d7d2a56748ab" ;
         tai:belongsTo ?org .
  ?defs tai:belongsTo ?model .
  ?choreo tai:belongsTo ?defs .

  ?task a bboExt:ChoreographyTask ;
        tai:belongsTo ?choreo ;
        bbo:name ?taskName .

  FILTER(
    CONTAINS(LCASE(STR(?taskName)), LCASE("process provisioning")) ||
    CONTAINS(LCASE(STR(?taskName)), LCASE("operations provisioning"))
  )
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?betweenName ?betweenTask ?pathLen WHERE {
  ?model a bboExt:Model ;
         tai:originalId "2f572d235e784b838fa0d7d2a56748ab" ;
         tai:belongsTo ?org .
  ?defs tai:belongsTo ?model .
  ?choreo tai:belongsTo ?defs .

  ?startTask a bboExt:ChoreographyTask ;
             tai:belongsTo ?choreo ;
             bbo:name ?startName .
  FILTER(LCASE(STR(?startName)) = LCASE("Process provisioning"))

  ?targetTask a bboExt:ChoreographyTask ;
              tai:belongsTo ?choreo ;
              bbo:name ?targetName .
  FILTER(LCASE(STR(?targetName)) = LCASE("Operations provisioning"))

  # Tasks reachable from start
  ?startTask ((^bbo:has_sourceRef)/bbo:has_targetRef)+ ?betweenTask .
  ?betweenTask a bboExt:ChoreographyTask ;
                tai:belongsTo ?choreo ;
                bbo:name ?betweenName .

  # Between tasks that can reach target
  ?betweenTask ((^bbo:has_sourceRef)/bbo:has_targetRef)+ ?targetTask .

  FILTER(?betweenTask != ?startTask)
  FILTER(?betweenTask != ?targetTask)

  # Approximate path length by counting edges from start to between and between to target
  BIND(1 as ?pathLen)
}
ORDER BY ?betweenName
LIMIT 25
